node GN_count_ge_threshold { has name: str; has val: int; has seen: bool = False; }

walker W_count_ge_threshold {
    has k: int;
    has count: int = 0;
    can step with GN_count_ge_threshold entry {
        if not here.seen { here.seen = True; if here.val >= self.k { self.count += 1; } visit [-->]; }
    }
}

def count_ge_threshold(spec: dict) -> int {
    adj: dict = dict(spec["adj"]); start: str = str(spec["start"]);
    vals: dict = dict(spec["vals"]);
    thr: int = int(spec["threshold"]);
    nodes: dict = {};
    for nm in adj.keys() { nodes[nm] = GN_count_ge_threshold(name=str(nm), seen=False, val=int(vals[nm])); }
    for (s, ts) in adj.items() { for t in list(ts) { if t not in nodes { nodes[t] = GN_count_ge_threshold(name=str(t), seen=False, val=int(vals[t])); } } }
    for (s, ts) in adj.items() { for t in list(ts) { nodes[s] ++> nodes[t]; } }
    w = nodes[start] spawn W_count_ge_threshold(k=thr);
    return w.count;
}

