def last_chain(spec: dict) -> int {
    items: list = list(spec["items"]);
    if len(items) == 0 { return 0; }
    cells: list = [];
    for v in items { cells.append(Cell(val=int(v))); }
    i: int = 0;
    while i < len(cells) - 1 { cells[i] ++> cells[i + 1]; i += 1; }
    w = cells[0] spawn LastC();
    return w.last;
}

